string patternNash(string S, string T, int n){
    int lenS = S.size();
    // Precompute occurrence positions for each character in S (assuming ASCII)
    vector<vector<int>> pos(128);
    for (int i = 0; i < lenS; i++){
        pos[S[i]].push_back(i);
    }
    // Check if every character in T exists in S
    for (char c : T){
        if(pos[c].empty()){
            return "NO";
        }
    }
    long long cycles = 1;
    int currentPos = -1;
    for (char c : T){
        auto &vec = pos[c];
        // Find upper_bound of current position in vec
        auto it = upper_bound(vec.begin(), vec.end(), currentPos);
        if(it == vec.end()){
            cycles++;
            if(cycles > n)return "NO";
            currentPos = vec[0];
        } else {
            currentPos = *it;
        }
    }
    return cycles <= n ? "YES" : "NO";
}

