function patternNash(S, T, n) {
    // Build map: for each character in S, store array of indices.
    const posMap = {};
    for (let i = 0; i < S.length; i++) {
        const ch = S[i];
        if (!posMap[ch]) {
            posMap[ch] = [];
        }
        posMap[ch].push(i);
    }

    // For each character in T, if it is not in S, return "NO"
    for (let i = 0; i < T.length; i++) {
        if (!posMap[T[i]]) {
            return "NO";
        }
    }

    // Function to perform binary search to find the smallest index in arr which is >= target.
    function binarySearch(arr, target) {
        let low = 0, high = arr.length;
        while (low < high) {
            const mid = Math.floor((low + high) / 2);
            if (arr[mid] >= target) {
                high = mid;
            } else {
                low = mid + 1;
            }
        }
        return low < arr.length ? arr[low] : -1;
    }

    let copiesUsed = 1; // Start with first copy.
    let indexInS = 0; // current index in S for matching.

    for (let i = 0; i < T.length; i++) {
        const ch = T[i];
        const indices = posMap[ch];
        // Find the next index in S that is >= indexInS for character ch.
        let pos = binarySearch(indices, indexInS);
        if (pos === -1) {
            // If not found in the current copy, use the first occurrence in the next copy.
            copiesUsed++;
            // If copies used exceeds n, we can return early.
            if (copiesUsed > n) {
                return "NO";
            }
            // Set indexInS to first occurrence +1.
            indexInS = indices[0] + 1;
        } else {
            // Found in current copy.
            indexInS = pos + 1;
        }
        // If we have reached the end of S, then switch to next copy automatically.
        if (indexInS >= S.length && i < T.length - 1) {
            copiesUsed++;
            if (copiesUsed > n) {
                return "NO";
            }
            indexInS = 0;
        }
    }

    return copiesUsed <= n ? "YES" : "NO";
}
